File: platform/browser-extension/src/resource-prompt-dispatch.ts

Resource read catch block: lines 84-91. Prompt render catch block: lines 175-181.

Both currently do:
```ts
catch (err: unknown) {
  const caughtError = err as { message?: string };
  return { type: 'error' as const, code: -32603, message: caughtError.message ?? '...' };
}
```

The tool dispatch path at platform/browser-extension/src/tool-dispatch.ts lines 245-274 has the correct pattern:
```ts
catch (err: unknown) {
  const caughtError = err as { message?: string; code?: string; retryable?: boolean; retryAfterMs?: number; category?: string };
  if (typeof caughtError.code !== 'string') {
    return { type: 'error' as const, code: -32603, message: caughtError.message ?? 'Tool execution failed' };
  }
  const data: { code: string; retryable?: boolean; retryAfterMs?: number; category?: string } = { code: caughtError.code };
  if (typeof caughtError.retryable === 'boolean') data.retryable = caughtError.retryable;
  if (typeof caughtError.retryAfterMs === 'number') data.retryAfterMs = caughtError.retryAfterMs;
  if (typeof caughtError.category === 'string') data.category = caughtError.category;
  return { type: 'error' as const, code: -32603, message: caughtError.message ?? '...', data };
}
```

Apply the same pattern to both catch blocks. Update the error message fallback to match ('Resource read failed' and 'Prompt render failed' respectively).
